  ('heelevel3-d30bcefc-moex-00032', 'heelevel3-d30bcefc', 'heelevel3-d30bcefc-moex-113-d3ff7f6b', 'sub-heelevel3-d30bcefc-01', NULL, 'single_choice', '假設本國可生產10單位X產品或20單位Y產品，而外國可生產10單位X產品或10單位Y產 品，且兩國從事國際貿易。若今外國之Y產品生產發生技術進步，變為與本國相同，亦可生產10 單位X產品或20單位Y產品，下列何者錯誤？', '["技術進步發生後，兩國無法透過國際貿易而得利", "技術進步發生後，兩國境內之產品相對價格相同", "技術進步發生後，本國福利水準下降", "技術進步發生後，外國福利水準不變"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:48+00:00", "source_pdf_sha1": "5eb67721d51d", "answer_pdf_sha1": "0e7bbb6b55ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0807", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "企業管理"}'::jsonb, NULL),
  ('heelevel3-d30bcefc-moex-00033', 'heelevel3-d30bcefc', 'heelevel3-d30bcefc-moex-113-d3ff7f6b', 'sub-heelevel3-d30bcefc-01', NULL, 'single_choice', '假設鳳梨釋迦市場的供需法則均成立。由於鳳梨釋迦無法外銷，因此市場的均衡價格滑落到每顆 鳳梨釋迦的價格為40元。因此，政府決定對每顆鳳梨釋迦設定價格下限（pricefloor）為60元。 此政策對鳳梨釋迦的消費者剩餘及生產者剩餘的影響為何？', '["消費者剩餘減少，但生產者剩餘的變化則不確定", "消費者剩餘增加，但生產者剩餘的變化則不確定", "消費者剩餘減少，且生產者剩餘增加", "消費者剩餘增加，且生產者剩餘增加"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:48+00:00", "source_pdf_sha1": "5eb67721d51d", "answer_pdf_sha1": "0e7bbb6b55ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0807", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "企業管理"}'::jsonb, NULL),
  ('heelevel3-d30bcefc-moex-00034', 'heelevel3-d30bcefc', 'heelevel3-d30bcefc-moex-113-d3ff7f6b', 'sub-heelevel3-d30bcefc-01', NULL, 'single_choice', '對於一般廠商來說，廣告支出與研發支出的屬性屬於沉沒成本。短期而言，當廣告活動或是研發 活動的支出費用上升時，一般廠商的：', '["邊際成本線、平均成本線均不變", "邊際成本線上移，平均成本線不變", "邊際成本線不變，平均成本線上移", "邊際成本線、平均成本線均上移 32260 32760"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:48+00:00", "source_pdf_sha1": "5eb67721d51d", "answer_pdf_sha1": "0e7bbb6b55ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0807", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "企業管理"}'::jsonb, NULL),
  ('heelevel3-d30bcefc-moex-00035', 'heelevel3-d30bcefc', 'heelevel3-d30bcefc-moex-113-d3ff7f6b', 'sub-heelevel3-d30bcefc-01', NULL, 'single_choice', '假設消費者的效用函數為U(X,Y)=XY+4，其中X和Y為財貨的消費量。當所得是$100，X和Y 的價格都是$2時，在效用極大化下，X財貨和Y財貨數量的最適選擇為何？', '["X=50，Y=50", "X=30，Y=20", "X=20，Y=30", "X=25，Y=25"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:48+00:00", "source_pdf_sha1": "5eb67721d51d", "answer_pdf_sha1": "0e7bbb6b55ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0807", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "企業管理"}'::jsonb, NULL),
  ('heelevel3-d30bcefc-moex-00036', 'heelevel3-d30bcefc', 'heelevel3-d30bcefc-moex-113-d3ff7f6b', 'sub-heelevel3-d30bcefc-01', NULL, 'single_choice', '假設美麗國廠商在本國與外國僱用勞工生產成衣，在某一固定產量下，每位本國與外國勞工的邊 際生產力分別為10與5，每位本國與外國勞工的薪資分別為5與2。下列敘述何者錯誤？', '["在此固定產量下，以外國勞工替代本國勞工的邊際技術替代率為0.5", "若廠商增加1位外國勞工，同時減少1位本國勞工，產量會下降", "維持相同成本，廠商增加外國勞工的僱用，減少本國勞工的僱用，產量會下降", "本國勞工每塊錢的邊際生產力低於外國勞工"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:48+00:00", "source_pdf_sha1": "5eb67721d51d", "answer_pdf_sha1": "0e7bbb6b55ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0807", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "企業管理"}'::jsonb, NULL),
  ('heelevel3-d30bcefc-moex-00037', 'heelevel3-d30bcefc', 'heelevel3-d30bcefc-moex-113-d3ff7f6b', 'sub-heelevel3-d30bcefc-01', NULL, 'single_choice', '有關獨占性競爭廠商，下列何者錯誤？', '["獨占性競爭廠商會從事產品異質化，但創意也很容易被模仿", "獨占性競爭廠商有一定的訂價權力，隨著顧客忠誠度越高、訂價權力越大", "獨占性競爭廠商的訂價權力讓其在長期得以享受正的經濟利潤", "獨占性競爭廠商可以透過廣告來傳遞其產品異質化的訊息"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:48+00:00", "source_pdf_sha1": "5eb67721d51d", "answer_pdf_sha1": "0e7bbb6b55ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0807", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "企業管理"}'::jsonb, NULL),
  ('heelevel3-d30bcefc-moex-00038', 'heelevel3-d30bcefc', 'heelevel3-d30bcefc-moex-113-d3ff7f6b', 'sub-heelevel3-d30bcefc-01', NULL, 'single_choice', '假設政府通過一法令，要求廠商必須給予受雇勞工每小時200元的額外福利，若此一政策造成勞 動需求與勞動供給同時變動，則勞動市場之均衡有何變化？', '["均衡工資變動方向不確定，均衡勞動雇用量下降", "均衡工資變動方向不確定，均衡勞動雇用量上升", "均衡工資上升，均衡勞動雇用量變動方向不確定", "均衡工資下降，均衡勞動雇用量變動方向不確定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:48+00:00", "source_pdf_sha1": "5eb67721d51d", "answer_pdf_sha1": "0e7bbb6b55ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0807", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "企業管理"}'::jsonb, NULL)
